import React, { useState, useCallback, useEffect } from 'react';
import { Search, Music, X, ExternalLink, BookOpen, ChevronLeft, ChevronRight, Settings } from 'lucide-react';
import { Link } from 'react-router-dom';
import { fetchSongs, fetchSong } from '../services/api';

const LANGUAGES = ['All', 'English', 'Telugu', 'Hindi', 'Multilingual'];
const CATEGORIES = ['All', 'Worship', 'Praise', 'Hymn', 'Christmas', 'Easter', 'Communion', 'Other'];

function useDebounce(value, delay) {
  const [dv, setDv] = useState(value);
  useEffect(() => { const t = setTimeout(() => setDv(value), delay); return () => clearTimeout(t); }, [value, delay]);
  return dv;
}

export default function HomePage() {
  const [query, setQuery]       = useState('');
  const [lang, setLang]         = useState('All');
  const [cat, setCat]           = useState('All');
  const [sort, setSort]         = useState('songNumber');
  const [page, setPage]         = useState(1);
  const [data, setData]         = useState(null);
  const [loading, setLoading]   = useState(false);
  const [selected, setSelected] = useState(null);
  const [detail, setDetail]     = useState(null);
  const [tab, setTab]           = useState('english');

  const dq = useDebounce(query, 350);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const params = { page, limit: 18, sort };
      if (dq) params.q = dq;
      if (lang !== 'All') params.language = lang.toLowerCase();
      if (cat  !== 'All') params.category  = cat.toLowerCase();
      const res = await fetchSongs(params);
      setData(res);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  }, [dq, lang, cat, sort, page]);

  useEffect(() => { setPage(1); }, [dq, lang, cat, sort]);
  useEffect(() => { load(); }, [load]);

  const openSong = async (id) => {
    setSelected(id); setTab('english');
    const res = await fetchSong(id);
    setDetail(res.song);
  };
  const closeSong = () => { setSelected(null); setDetail(null); };

  const totalPages = data ? Math.ceil(data.total / 18) : 1;

  return (
    <>
      {/* HEADER */}
      <header className="header">
        <div className="header-inner">
          <div className="header-logo">
            <div className="header-logo-icon">✝</div>
            <div className="header-logo-text">
              <span className="header-logo-name">New Covenant Church</span>
              <span className="header-logo-sub">Songs Collection</span>
            </div>
          </div>

          <div className="search-wrap">
            <Search size={16} className="search-icon" />
            <input
              className="search-input"
              placeholder="Search songs, lyrics, authors…"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
            {query && (
              <button className="search-clear" onClick={() => setQuery('')}>
                <X size={14} />
              </button>
            )}
          </div>

          <div className="header-actions">
            <Link to="/admin" className="btn btn-gold" style={{ fontSize: 13 }}>
              <Settings size={14} /> Admin
            </Link>
          </div>
        </div>
      </header>

      {/* HERO (shown only when no search) */}
      {!query && (
        <section className="hero">
          <h1>Sing unto the <span>Lord</span> a new song</h1>
          <p>Browse our complete collection of worship songs in English, Telugu &amp; Hindi</p>
          <div className="hero-langs">
            {['English', 'తెలుగు', 'हिन्दी'].map((l) => (
              <span key={l} className="hero-lang-pill">{l}</span>
            ))}
          </div>
        </section>
      )}

      {/* FILTERS */}
      <div className="filters">
        <span className="filter-label">Language</span>
        {LANGUAGES.map((l) => (
          <button key={l} className={`filter-chip ${lang === l ? 'active' : ''}`} onClick={() => setLang(l)}>{l}</button>
        ))}
        <span className="filter-label" style={{ marginLeft: 8 }}>Category</span>
        {CATEGORIES.map((c) => (
          <button key={c} className={`filter-chip ${cat === c ? 'active' : ''}`} onClick={() => setCat(c)}>{c}</button>
        ))}
        <select className="form-select" style={{ width: 130, marginLeft: 8 }} value={sort} onChange={(e) => setSort(e.target.value)}>
          <option value="songNumber">By Number</option>
          <option value="title">A–Z</option>
          <option value="newest">Newest</option>
        </select>
        {data && <span className="filter-count">{data.total} songs</span>}
      </div>

      {/* SONGS GRID */}
      <section className="songs-section container">
        {loading ? (
          <div className="spinner" />
        ) : data?.songs?.length === 0 ? (
          <div className="empty">
            <div className="empty-icon">🎵</div>
            <h3>No songs found</h3>
            <p>Try a different search or filter</p>
          </div>
        ) : (
          <>
            <div className="songs-grid">
              {data?.songs?.map((song) => (
                <div key={song._id} className="song-card" onClick={() => openSong(song._id)}>
                  {song.songNumber && <div className="song-number">#{song.songNumber}</div>}
                  <div className="song-title">{song.title}</div>
                  {(song.titleTelugu || song.titleHindi) && (
                    <div className="song-title-alt">
                      {song.titleTelugu && <span style={{ fontFamily: 'var(--font-telugu)' }}>{song.titleTelugu}</span>}
                      {song.titleTelugu && song.titleHindi && ' · '}
                      {song.titleHindi  && <span style={{ fontFamily: 'var(--font-hindi)' }}>{song.titleHindi}</span>}
                    </div>
                  )}
                  <div className="song-meta">
                    <span className="badge badge-lang">{song.language}</span>
                    <span className="badge badge-cat">{song.category}</span>
                    {song.key && <span className="badge badge-lang">Key: {song.key}</span>}
                  </div>
                  {song.lyrics && (
                    <div className="song-lyrics-preview">
                      {song.lyrics.slice(0, 120)}…
                    </div>
                  )}
                </div>
              ))}
            </div>

            {/* PAGINATION */}
            {totalPages > 1 && (
              <div className="pagination">
                <button className="page-btn" disabled={page === 1} onClick={() => setPage(p => p - 1)}>
                  <ChevronLeft size={16} />
                </button>
                {Array.from({ length: Math.min(totalPages, 7) }, (_, i) => {
                  const p = i + 1;
                  return (
                    <button key={p} className={`page-btn ${page === p ? 'active' : ''}`} onClick={() => setPage(p)}>
                      {p}
                    </button>
                  );
                })}
                <button className="page-btn" disabled={page === totalPages} onClick={() => setPage(p => p + 1)}>
                  <ChevronRight size={16} />
                </button>
              </div>
            )}
          </>
        )}
      </section>

      {/* SONG DETAIL MODAL */}
      {selected && (
        <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && closeSong()}>
          <div className="modal">
            <div className="modal-header" style={{ position: 'relative' }}>
              <button className="modal-close" onClick={closeSong}><X size={16} /></button>
              {detail ? (
                <>
                  {detail.songNumber && <div style={{ fontSize: 12, opacity: 0.6, marginBottom: 4 }}>#{detail.songNumber}</div>}
                  <h2>{detail.title}</h2>
                  <p>
                    {detail.author && `By ${detail.author}  ·  `}
                    {detail.category}  ·  {detail.language}
                    {detail.key && `  ·  Key: ${detail.key}`}
                  </p>
                  <div style={{ display: 'flex', gap: 10, marginTop: 14, flexWrap: 'wrap' }}>
                    {detail.youtubeUrl && (
                      <a href={detail.youtubeUrl} target="_blank" rel="noreferrer"
                         className="btn btn-gold" style={{ fontSize: 13, padding: '7px 14px' }}>
<ExternalLink size={14} /> Watch on YouTube                      </a>
                    )}
                    {detail.chords && (
                      <button className="btn btn-outline" style={{ fontSize: 13, padding: '7px 14px', borderColor: 'rgba(255,255,255,0.4)', color: '#fff' }}>
                        <BookOpen size={14} /> View Chords
                      </button>
                    )}
                  </div>
                </>
              ) : (
                <div style={{ color: 'rgba(255,255,255,0.6)' }}>Loading…</div>
              )}
            </div>

            {detail && (
              <>
                <div className="modal-tabs">
                  {[['english','English'],['telugu','తెలుగు'],['hindi','हिन्दी']].map(([key, label]) => (
                    (key === 'english' ? detail.lyrics : key === 'telugu' ? detail.lyricsTelugu : detail.lyricsHindi) && (
                      <button key={key} className={`modal-tab ${tab === key ? 'active' : ''}`} onClick={() => setTab(key)}>
                        {label}
                      </button>
                    )
                  ))}
                </div>
                <div className="modal-body">
                  {tab === 'english' && <pre className="lyrics-block">{detail.lyrics}</pre>}
                  {tab === 'telugu'  && <pre className={`lyrics-block telugu`}>{detail.lyricsTelugu}</pre>}
                  {tab === 'hindi'   && <pre className={`lyrics-block hindi`}>{detail.lyricsHindi}</pre>}
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </>
  );
}
